public class DataService : MonoBehaviour
{
    public static DataService Instance { get; private set; }

    public IAuthService Auth { get; private set; }
    public IProgressService Progress { get; private set; }
    public IRewardService Reward { get; private set; }
    public IAdminDataService Admin { get; private set; }

    void Awake()
    {
        if (Instance != null) { Destroy(gameObject); return; }
        Instance = this;
        DontDestroyOnLoad(gameObject);

        // 1. Infrastructure
        Db = new DBGateway();
        var dbCore = (IDBGateway)Db;

        // 2. Repository (DBGateway 주입)
        UserRepository      = new UserRepository(dbCore);
        ProgressRepository  = new ProgressRepository(dbCore);
        InventoryRepository = new InventoryRepository(dbCore);
        ResultRepository    = new ResultRepository(dbCore);

        // 3. Service (Repository 주입, Service 간 조합 허용)
        Auth     = new AuthService(UserRepository);
        Progress = new LocalProgressService(
            ProgressRepository, UserRepository, ResultRepository);
        Reward   = new LocalRewardService(
            InventoryRepository, UserRepository, Progress);
    }
}

public abstract class ProblemStepBase : MonoBehaviour
{
    [SerializeField] protected ProblemContext context;
    [SerializeField] protected StepKeyConfig stepKeyConfig;

    public abstract void OnStepEnter();
    public virtual void OnStepExit() { }

    protected void SaveAttempt(object body)
    {
        var key = stepKeyConfig.BuildKey(
            ProblemSession.CurrentTheme,
            ProblemSession.CurrentProblemIndex);

        DataService.Instance.Progress
            .SaveStepAttemptForCurrentUser(key, body);
    }

    protected void SaveReward(object body, string itemId, string itemName)
    {
        DataService.Instance.Reward
            .SaveRewardForCurrentUser(
                ProblemSession.CurrentTheme,
                ProblemSession.CurrentProblemIndex,
                body, itemId, itemName);
    }
}

public abstract class MultipleChoiceStepBase<T> : ProblemStepBase
{
    [SerializeField] protected StepCompletionGate completionGate;

    public abstract int QuestionCount { get; }
    public abstract T GetQuestion(int index);
    public abstract int GetCorrectOptionIndex(T q);
}

public class MicRecordingIndicator : MonoBehaviour
{
    [SerializeField] Image targetImage;
    [SerializeField] Sprite idleSprite;
    [SerializeField] Sprite recordingSprite;
    [SerializeField] Sprite recognizingSprite;
    [SerializeField] string[] keywords;

    public event Action<int> OnKeywordMatched;
    public event Action<string> OnNoMatch;

    void OnEnable()
    {
        STTManager.Instance.OnPartialResult += HandlePartial;
        STTManager.Instance.OnFinalResult   += HandleFinal;
    }

    public void ToggleRecording()
    {
        if (STTManager.Instance.IsRecording)
        {
            STTManager.Instance.StopRecording(skipProcessing: false);
            SetState(recognizingSprite);
        }
        else
        {
            STTManager.Instance.SetPromptHint(keywords);
            STTManager.Instance.StartRecording();
            SetState(recordingSprite);
        }
    }

    void HandleFinal(string text)
    {
        var (bestIdx, score) = KeywordMatcher.FindBestMatch(text, keywords);
        if (score >= 0.6f) OnKeywordMatched?.Invoke(bestIdx);
        else               OnNoMatch?.Invoke(text);
        SetState(idleSprite);
    }
}

public class DialogueSequencer : MonoBehaviour
{
    [SerializeField] int[] enterTextIds;
    [SerializeField] int[] completedTextIds;
    [SerializeField] Text dialogueText;
    [SerializeField] Button nextDialogueBtn;
    [SerializeField] Button nextStepBtn;

    public event Action OnEnterSequenceDone;
    public event Action OnEnterComplete;

    int _index;
    int[] _current;

    public void PlaySequence(int[] ids, Action onSeq, Action onComplete)
    {
        _current = ids;
        _index = 0;
        OnEnterSequenceDone = onSeq;
        OnEnterComplete     = onComplete;
        ShowAt(_index);
    }

    void ShowAt(int i)
    {
        int textId = _current[i];
        dialogueText.text = ProblemRuntime.L(textId);
        SoundManager.Instance.PlayTTS(textId);
    }

    public void OnNextDialogueClicked()
    {
        if (SoundManager.Instance.IsTTSPlaying) return;

        _index++;
        if (_index >= _current.Length) OnEnterSequenceDone?.Invoke();
        else ShowAt(_index);
    }
}

public class AuthService : IAuthService
{
    private readonly IUserRepository _users;
    private const int BcryptWorkFactor = 10;

    public AuthService(IUserRepository users)
    {
        _users = users ?? throw new ArgumentNullException(nameof(users));
        EnsureSuperAdmin();
    }

    public Result<User> Login(string email, string password)
    {
        try
        {
            var e = AuthValidator.NormalizeEmail(email);
            if (!AuthValidator.IsValidEmail(e))
                return Result<User>.Fail(AuthError.EmailInvalid);

            var u = _users.FindActiveUserByEmail(e);
            if (u == null)
                return Result<User>.Fail(AuthError.NotFoundOrInactive);

            bool ok = BCrypt.Net.BCrypt.Verify(password, u.PasswordHash);
            if (!ok)
                return Result<User>.Fail(AuthError.PasswordMismatch);

            return Result<User>.Success(u);
        }
        catch (Exception ex)
        {
            Debug.LogError($"[AuthService] Login error: {ex}");
            return Result<User>.Fail(AuthError.Internal);
        }
    }

    public Result SignUp(string name, string email, string password)
    {
        if (_users.ExistsEmail(email))
            return Result.Fail(AuthError.EmailDuplicated);

        var hash = BCrypt.Net.BCrypt.HashPassword(password, BcryptWorkFactor);
        _users.InsertUser(new User { Name = name, Email = email, PasswordHash = hash });
        return Result.Success();
    }
}
